    {"id": 5, "name": "Erik Svec", "age": 18, "image": "https://static.encyclopedia.warthunder.com/images/fr_hotchkiss_h39.png"},
    {"id": 6, "name": "Filip Hric", "age": 17, "image": "https://static.encyclopedia.warthunder.com/images/us_m22_locust.png"},
